# define similarity metrics: normalized LCS length / length of target, or token-based F1?
def lcs_length(a, b):
    # dynamic programming
    n, m = len(a), len(b)
    dp = [0] * (m + 1)
    for i in range(1, n + 1):
        prev = 0
        for j in range(1, m + 1):
            tmp = dp[j]
            if a[i-1] == b[j-1]:
                dp[j] = prev + 1
            else:
                dp[j] = max(dp[j], dp[j-1])
            prev = tmp
    return dp[m]

def sim_ratio(a, b):
    a_norm = normalize_arabic(a)
    b_norm = normalize_arabic(b)
    if not a_norm or not b_norm:
        return 0.0
    lcs = lcs_length(a_norm, b_norm)
    # normalized by average length maybe?
    return lcs / max(len(a_norm), 1)

