def tokenize(s):
    s = normalize_arabic(s)
    return s.split()

def token_f1(a, b):
    ta = tokenize(a)
    tb = tokenize(b)
    if not ta or not tb:
        return 0.0
    ca = collections.Counter(ta)
    cb = collections.Counter(tb)
    # compute overlap counts
    overlap = sum(min(ca[t], cb[t]) for t in ca)
    prec = overlap / max(len(ta), 1)
    rec = overlap / max(len(tb), 1)
    if prec + rec == 0:
        f1 = 0.0
    else:
        f1 = 2 * prec * rec / (prec + rec)
    return f1, prec, rec, overlap, len(ta), len(tb)

def longest_common_substring_len(a, b):
    # dynamic programming for LCSUBSTR contiguous
    a = normalize_arabic(a)
    b = normalize_arabic(b)
    n, m = len(a), len(b)
    dp = [0]*(m+1)
    best = 0
    for i in range(1, n+1):
        prev = 0
        for j in range(1, m+1):
            temp = dp[j]
            if a[i-1] == b[j-1]:
                dp[j] = prev + 1
                if dp[j] > best: best = dp[j]
            else:
